let idCounter = 0;

export type SingleLineQuestionData = {
    kind: 'singleLine',
    id: string,
    title: string,
    responses: string[],
}

function SingleLineQuestionData(id: string, title: string, responses: string[]): SingleLineQuestionData {
    return {
        kind: 'singleLine',
        id: id,
        title: title,
        responses: responses
    }
}

export type MultiLineQuestionData = {
    kind: 'multiLine',
    id: string,
    title: string,
    questions: string[],
    responses: string[]
}

function MultiLineQuestionData(id: string, title: string, questions: string[], responses: string[]): MultiLineQuestionData {
    return {
        kind: 'multiLine',
        id: id,
        title: title,
        questions: questions,
        responses: responses
    }
}

