import { Fragment, h } from 'preact';
import * as model from "../model/the-test-model";
import { MultiLineQuestionData, QuestionData, QuestionnaireData } from "../model/questionnaire";

function ResponseView(response: string, isSelected: boolean, onClick: () => void) {
	let clazz = "pure-button" + (isSelected ? " pure-button-active pure-button-primary" : "");
	return (
		<div>
			<button class={clazz} onClick={onClick}>{response}</button>
		</div>
	)
}

function MultiLineQuestionView(question: model.Question<MultiLineQuestionData>) {
	let questions2 = question.content.questions.map((q, qix) => {
		let options = question.content.responses.map((r, ix) => ResponseView(
			r,
			question.choice[qix] == ix,
			() => model.dispatch({ kind: 'multiLineAnswer', questionId: question.content.id, qrIndex: [qix, ix] })
		)
		)
		return (
			<div>
				<h4>{q}</h4>
				<div class="pure-button-group" role="group">{options}</div>
			</div>
		)
	})
	return <div>
		<h2>{question.content.title}</h2>
		{questions2}
	</div>
}

function QuestionView(question: model.Question<QuestionData>) {
	switch (question.content.kind) {
		case "singleLine": {
			let responseViews = question.content.responses.map(
				(r, ix) => ResponseView(
					r,
					question.choice == ix,
					() => model.dispatch({ kind: 'answer', questionId: question.content.id, answerIndex: ix })
				)
			)
			return (
				<div>
					<h2>{question.content.title}</h2>
					<div>
						{responseViews}
					</div>
				</div>
			)
		}
		case "multiLine": {
			return MultiLineQuestionView(question as model.Question<MultiLineQuestionData>)
		}
	}
}

function latentActivity(value: number): string {
	switch (value) {
		case 1: return "Явно удовлетворён"
		case 2: return "Скорее удовлетворён, чем не удовлетворён"
		case 3: return "Неопределенное отношение"
		case 4: return "Скорее не удовлетворен, чем удовлетворен"
		case 5: return "Явно не удовлетворен"
		case 6: return "Противоречивое отношение"
	}
}

function selfRealization(value: number): string {
	switch (value) {
		case 1: return "Высокопродуктивная самореализация"
		case 2: return "Среднепродуктивная самореализация"
		case 3: return "Малопродуктивная самореализация"
		case 4: return "Непродуктивная самореализация"
	}
}

const App = () => {
	let currentState = model.state.value;
	if (currentState.kind == 'finished') {
		return (<div>
			<h1>Спасибо за участие!</h1>
			<p>Отношение к работе: {latentActivity(currentState.latentActivityRelation)}</p>
			<p>Самореализация: {selfRealization(currentState.selfRealizationRelation)}</p>
		</div>)
	} else {
		let questionViews = Object.values(currentState.questionnaire).map(QuestionView);
		let errorView;
		return (<Fragment>
			<div>
				{questionViews}
			</div>
			<div>
				{currentState.showIncompleteError &&
					<h4 class="incomplete-error">
						Пожалуйста, ответьте на все вопросы.
					</h4>
				}
				<button class="button-xlarge pure-button button-success button-finish" onClick={() => model.dispatch({ kind: 'finish' })}>Завершить</button>
			</div>
		</Fragment>)
	}
}

export default App;
