import { Signal, signal } from "@preact/signals";
import { QuestionData, SingleLineQuestionData, QuestionnaireData, MultiLineQuestionData } from "./questionnaire"
import { shuffle } from "./utils";
import { latentActivityRelationTable } from "./latent_activity_relation";
import { selfRealizationRelationTable } from "./self_realization_relation";
import { generalSatisfactionRelationTable } from "./general_satisfaction_relation";

export type Response = {
	content: string
}

export function Response(content: string): Response {
	return {
		content: content
	}
}

type None = 'none'

type SingleLineChoice = None | number;
type MultiLineChoice = { [questionIndex: number]: SingleLineChoice };

type Choice<QD> = QD extends SingleLineQuestionData ? SingleLineChoice : (QD extends MultiLineQuestionData ? MultiLineChoice : never);

export type Question<QD extends QuestionData> = {
	content: QD,
	choice: Choice<QD>
}

export type AQuestion = Question<QuestionData>

export function Question<QD extends QuestionData>(content: QD): Question<QD> {
	let choice;
	switch(content.kind) {
		case "singleLine": {
			choice = 'none';
			break;
		}
		case "multiLine": {
			choice = { ...content.responses.map(_ => 'none') };
			break;
		}
	}
	return {
		content: content,
		choice: choice
	}
}

export type Finished = {
	kind: 'finished',
	latentActivityRelation: number,
	selfRealizationRelation: number,
	psychologicalStateRelation: number,
	responsibility: number,
	tolerance: number
}

export type Progress = {
	kind: 'progress',
	questionnaire: { [id: string]: AQuestion },
	showIncompleteError: boolean
}

export type State = Finished | Progress;

export function State(questionnaire: Question<QuestionData>[]): Progress {
	let qMap = Object.fromEntries(questionnaire.map(q => [q.content.id, q]))
	return {
		kind: 'progress',
		questionnaire: qMap,
		showIncompleteError: false
	}
}

export const state: Signal<State> = signal(
	State(
		QuestionnaireData.map(q => Question(q))
	)
);

type SingleLineAnswer = {
	kind: 'answer';
	questionId: string;
	answerIndex: number;
}

type MultiLineAnswer = {
	kind: 'multiLineAnswer';
	questionId: string;
	qrIndex: [number, number]
}

type Finish = {
	kind: 'finish';
}

export type Event = SingleLineAnswer | MultiLineAnswer | Finish;

export function dispatch(event: Event) {
	let newState: State;
	switch(event.kind) {
		case 'answer': {
			let currentState = state.value as Progress;
			let question = currentState.questionnaire[event.questionId]
			let newQuestion: Question<QuestionData> = {
				...question,
				choice: event.answerIndex,
			}
			newState = {
				...currentState,
				questionnaire: {
					...currentState.questionnaire,
					[question.content.id]: newQuestion
				}
			}
			break;
		}
		case 'multiLineAnswer': {
			let currentState = state.value as Progress;
			let question = currentState.questionnaire[event.questionId] as Question<MultiLineQuestionData>
			let newChoice = {
				...question.choice,
				[event.qrIndex[0]]: event.qrIndex[1]
			}
			let newQuestion: Question<MultiLineQuestionData> = {
				...question,
				choice: newChoice
			}
			newState = {
				...currentState,
				questionnaire: {
					...currentState.questionnaire,
					[question.content.id]: newQuestion
				}
			}
			break;
		}
		case 'finish': {
			let currentState = state.value as Progress;
			let qv = Object.values(currentState.questionnaire);
			if (qv.every(q => {
				return (q.content.kind == 'singleLine' && q.choice != 'none') || (q.content.kind == 'multiLine' && Object.values(q.choice).every(c => c != 'none'))
			})) {
				let q = currentState.questionnaire;
				newState = {
					kind: 'finished',
					latentActivityRelation: latentActivityRelationTable[
						q["job_change_desire"].choice as number
					][
						q["profession_liking"].choice as number
					][
						q["reentrance_inquiry"].choice as number
					],
					selfRealizationRelation: selfRealizationRelationTable[
						q["professionalism_improvement"].choice as number
					][
						q["work_goals"].choice as number
					][
						calculateMotivationalComplex(q["work_motivation"] as Question<MultiLineQuestionData>)
					],
					psychologicalStateRelation: generalSatisfactionRelationTable[
						q["day_end_occupation"].choice as number
					][
						q["happiness_frequence"].choice as number
					][
						q["life_reentrance"].choice as number
					],
					responsibility: calculateResponsibility(q["who_to_blame"].choice as number, q["own_ideas_benefits"].choice as number),
					tolerance: calculateTolerance(q["people_around"].choice as number, q["colleague_communication"].choice as number)
				};
			} else
				newState = {
					...currentState,
					showIncompleteError: true
				}
		}
	}
	state.value = newState;
}

function calculateMotivationalComplex(q: Question<MultiLineQuestionData>): number {
	let c = q.choice as number[]

	let vm = (c[5] + c[6]) / 2.0
	let vpm = (c[0] + c[1] + c[4]) / 3.0
	let vom = (c[2] + c[3]) / 2.0

	if (vm >= vpm && vpm > vom) {
		return 0;
	} else if (vm < vpm && vpm < vom) {
		return 2;
	} else return 1;
}

function calculateResponsibility(q1: number, q2: number): number {
	function map(q: number): number {
		switch (q) {
			case 0: return 10;
			case 1: return 1;
			case 2: return 5;
		}
	}
	let r = map(q1) + map(q2)
	if (r == 20) return 0
	if (r >= 10) return 1
	return 2
}

function calculateTolerance(q3: number, q4: number): number {
	let v3: number;
	switch (q3) {
		case 1:
		case 2:
			v3 = 10;
			break;
		case 0:
		case 4:
			v3 = 1;
			break;
		case 3:
			v3 = 5;
			break;
	}

	let v4: number;
	switch (q4) {
		case 0:
			v4 = 10;
			break;
		case 1:
			v4 = 1;
			break;
		case 2:
			v4 = 5;
			break;
	}
	let r = v3 + v4;
	if (r == 20) return 0
	if (r >= 10) return 1
	return 2
}